messages.content:
你遇到的问题是因为 `text_embed_udf` 和 `image_embed_udf` 各自创建了独立的 UDF 实例,导致 `JinaEmbeddingsV4VLLM` 模型被加载了两次。以下是几种优化方案:

## 方案1: 创建统一的多模态 UDF (推荐)

```python
# image/embedding.py 和 text/embedding.py 中添加

def create_jina_embeddings_v4_vllm_multimodal_udf(
    batch_size: Optional[int] = None,
    concurrency: Optional[int] = None,
    num_cpus: Optional[int] = None,
    num_gpus: Optional[int] = None,
):
    @daft.udf(
        return_dtype=embed_types,
        concurrency=concurrency,
        num_cpus=num_cpus,
        num_gpus=num_gpus,
        batch_size=batch_size,
    )
    class JinaEmbeddingsV4VLLMMultimodalUDF:
        def __init__(self):
            from src.models.jina_embeddings_v4_vllm import JinaEmbeddingsV4VLLM
            self.model = JinaEmbeddingsV4VLLM()

        def __call__(self, modality_col: daft.DataFrame, text_col: daft.DataFrame, image_col: daft.DataFrame) -> daft.DataFrame:
            modalities = modality_col.to_pylist()
            texts = text_col.to_pylist()
            images = image_col.to_pylist()

            embeddings_list = []
            for modality, text, image in zip(modalities, texts, images):
                if modality == "text":
                    emb = self.model.embed_texts([text])[0]
                elif modality == "image":
                    emb = self.model.embed_images([image])[0]
                else:
                    raise ValueError(f"Unsupported modality: {modality}")
                embeddings_list.append(emb)

            return np.array(embeddings_list)

    return JinaEmbeddingsV4VLLMMultimodalUDF.with_init_args()

# pipeline.py 中使用
def main():
    num_rows = 1000
    dim = 2048

    mock_df = generate_mock_data(num_rows, dim)

    # 创建统一的多模态 UDF
    multimodal_embed_udf = create_jina_embeddings_v4_vllm_multimodal_udf(
        batch_size=32,
        num_cpus=8, 
        num_gpus=1, 
        concurrency=1
    )

    # 一次性处理所有数据
    processed_df = mock_df.with_column(
        "mm_embedding",
        multimodal_embed_udf(mock_df["modality"], mock_df["text"], mock_df["image"])
    )
    processed_df = processed_df.exclude('image')
    processed_df.show()
```

## 方案2: 批量处理优化 (更高效)

```python
def create_jina_embeddings_v4_vllm_multimodal_udf(
    batch_size: Optional[int] = None,
    concurrency: Optional[int] = None,
    num_cpus: Optional[int] = None,
    num_gpus: Optional[int] = None,
):
    @daft.udf(
        return_dtype=embed_types,
        concurrency=concurrency,
        num_cpus=num_cpus,
        num_gpus=num_gpus,
        batch_size=batch_size,
    )
    class JinaEmbeddingsV4VLLMMultimodalUDF:
        def __init__(self):
            from src.models.jina_embeddings_v4_vllm import JinaEmbeddingsV4VLLM
            self.model = JinaEmbeddingsV4VLLM()

        def __call__(self, modality_col: daft.DataFrame, text_col: daft.DataFrame, image_col: daft.DataFrame) -> daft.DataFrame:
            modalities = modality_col.to_pylist()
            texts = text_col.to_pylist()
            images = image_col.to_pylist()

            # 分组处理
            text_indices = [i for i, m in enumerate(modalities) if m == "text"]
            image_indices = [i for i, m in enumerate(modalities) if m == "image"]

            # 批量推理
            embeddings = np.zeros((len(modalities), self.model.embedding_dim), dtype=np.float32)

            if text_indices:
                text_batch = [texts[i] for i in text_indices]
                text_embeddings = self.model.embed_texts(text_batch)
                for idx, emb in zip(text_indices, text_embeddings):
                    embeddings[idx] = emb

            if image_indices:
                image_batch = [images[i] for i in image_indices]
                image_embeddings = self.model.embed_images(image_batch)
                for idx, emb in zip(image_indices, image_embeddings):
                    embeddings[idx] = emb

            return embeddings

    return JinaEmbeddingsV4VLLMMultimodalUDF.with_init_args()
```

## 方案3: 如果必须分开处理,使用共享模型实例

```python
# 创建一个单例模型管理器
class JinaModelManager:
    _instance = None
    _model = None

    @classmethod
    def get_model(cls):
        if cls._model is None:
            from src.models.jina_embeddings_v4_vllm import JinaEmbeddingsV4VLLM
            cls._model = JinaEmbeddingsV4VLLM()
        return cls._model

# 修改 text UDF
def create_jina_embeddings_v4_vllm_text_udf(...):
    @daft.udf(...)
    class JinaEmbeddingsV4VLLMTextUDF:
        def __init__(self):
            self.model = JinaModelManager.get_model()  # 使用共享实例

        def __call__(self, text_col: daft.DataFrame) -> daft.DataFrame:
            texts_list = text_col.to_pylist()
            embeddings = self.model.embed_texts(texts_list)
            return embeddings
    return JinaEmbeddingsV4VLLMTextUDF.with_init_args()

# 修改 image UDF (同样使用 JinaModelManager.get_model())
```

## 方案4: 使用 Ray Actor 共享模型 (最佳性能)

```python
import ray

@ray.remote(num_gpus=1)
class JinaEmbeddingActor:
    def __init__(self):
        from src.models.jina_embeddings_v4_vllm import JinaEmbeddingsV4VLLM
        self.model = JinaEmbeddingsV4VLLM()

    def embed_texts(self, texts):
        return self.model.embed_texts(texts)

    def embed_images(self, images):
        return self.model.embed_images(images)

# 在 pipeline.py 中
def main():
    # 创建共享的 actor
    embedding_actor = JinaEmbeddingActor.remote()

    mock_df = generate_mock_data(num_rows, dim)

    # 使用 map_batches 手动处理
    def process_batch(batch):
        text_mask = batch["modality"] == "text"
        image_mask = batch["modality"] == "image"

        embeddings = np.zeros((len(batch), 2048))

        if text_mask.any():
            text_embs = ray.get(embedding_actor.embed_texts.remote(
                batch[text_mask]["text"].tolist()
            ))
            embeddings[text_mask] = text_embs

        if image_mask.any():
            image_embs = ray.get(embedding_actor.embed_images.remote(
                batch[image_mask]["image"].tolist()
            ))
            embeddings[image_mask] = image_embs

        batch["mm_embedding"] = embeddings.tolist()
        return batch

    processed_df = mock_df.map_batches(process_batch, batch_size=32)
```

## 推荐方案

**优先使用方案2 (批量处理的多模态UDF)**,因为:
1. ✅ 只加载一次模型
2. ✅ 充分利用批量推理性能
3. ✅ 代码简洁,易于维护
4. ✅ 与现有架构兼容

如果需要更高的并发性能,考虑**方案4 (Ray Actor)**。
